sp_widget.client_script:
function CaseSubmissionWidgetController($scope, $http) {
    /*
     * Case Submission Widget - client-side AngularJS controller.
     *
     * Implements the case-submission user interaction described in
     * AAP Section 0.4.4 ("Page 1 - Case Submission: a simple form
     * with five inputs (subject, type, description, requester_name,
     * requester_email). On submit, calls the scripted REST endpoint,
     * displays a confirmation panel showing the returned case number
     * and a friendly 'Your case has been submitted' message.").
     *
     * Exposed properties (template-bound):
     *   c.formData       - object with five string keys (subject, type,
     *                      description, requester_name, requester_email).
     *                      Each key is initialized to '' (empty string).
     *                      Each key is bound to its corresponding form
     *                      input via ng-model.
     *   c.submitting     - boolean; true while the in-flight $http.post
     *                      request is pending. Drives the button's
     *                      ng-disabled and the "Submitting..." text.
     *   c.errorMessage   - string; non-empty when the most recent
     *                      submit attempt failed. Drives the alert
     *                      panel's ng-if="c.errorMessage". Reset to
     *                      '' at the start of every new submit.
     *   c.data           - object provided by the Service Portal
     *                      framework, populated server-side by the
     *                      <script> body. Contains:
     *                        c.data.confirmationWidget - the embedded
     *                          confirmation widget instance loaded via
     *                          $sp.getWidget(). The success callback
     *                          mutates c.data.confirmationWidget.options.
     *                          number to pass the auto-generated case
     *                          number to the embedded widget.
     *                        c.data.submitted - boolean; flipped to
     *                          true after a successful POST. Drives
     *                          the conditional swap from the form panel
     *                          to the embedded confirmation widget panel.
     *                        c.data.submittedNumber - string; mirrors
     *                          the case number for any consumers that
     *                          want it directly off c.data (defense-in-
     *                          depth, in case the embedded widget's
     *                          options object is replaced rather than
     *                          mutated by some future refactor).
     *
     * Exposed method (template-bound):
     *   c.submit()       - executes the case submission. Issues
     *                      POST /api/x_casemgmt/case_submit with the
     *                      5-field whitelisted payload via $http.post().
     *                      On success (HTTP 201 with non-empty number),
     *                      sets c.data.submitted = true and mutates the
     *                      embedded confirmation widget's options.number
     *                      to the returned case number. On any error
     *                      (HTTP 4xx/5xx, network, missing number),
     *                      sets c.errorMessage to a generic, non-leaking
     *                      message so the verbatim alert is rendered.
     *
     * Design rationale:
     *   - controller-as syntax (`var c = this`) per AAP Section 0.5.1's
     *     widget-authoring conventions and per the sibling lookup widget
     *     at ./sp_widget_x_[scope]_case_lookup_widget.xml.
     *   - $http (NOT fetch): Service Portal widgets run in AngularJS
     *     1.5.x context; $http is the canonical HTTP client. fetch()
     *     would bypass AngularJS's digest cycle and require manual
     *     $scope.$apply() handling.
     *   - Strict 5-key payload (defense-in-depth): the POST body is
     *     constructed by enumerating exactly the five whitelisted
     *     fields, NOT by passing c.formData wholesale. Even if a future
     *     refactor accidentally adds a sixth key to c.formData, the
     *     POST body would still contain exactly the five whitelisted
     *     fields. The server-side Script Include also drops any
     *     non-whitelisted keys as a fallback, but the client-side
     *     enumeration provides the first line of defense.
     *   - Generic error message in template, NOT echoed from server:
     *     the message "Submission failed. Please try again." is
     *     hardcoded in this controller via direct assignment to
     *     c.errorMessage. This controller deliberately does NOT pass
     *     error.data.error or error.statusText to the template - the
     *     server's error body is NEVER trusted by the client. This
     *     matches the information-leakage hardening pattern used by
     *     the sibling lookup widget.
     *   - Identical handling of all HTTP errors: information-leakage
     *     hardening. 400 (validation), 500 (server-error), 0 (network),
     *     and "missing number on HTTP 200" all set the same generic
     *     error. An attacker cannot distinguish "validation failed"
     *     from "server error" from "network down" via the UX.
     *   - c.submitting flag: prevents double-submit race conditions if
     *     the user clicks the button twice quickly OR presses Enter
     *     inside an input field while a request is in flight. The
     *     ng-disabled binding on the button is the primary guard;
     *     the early-return inside c.submit() is the defense-in-depth
     *     fallback in case the disabled state is bypassed by a
     *     keyboard event in an edge browser.
     *   - String() coercion on response.data.number: ensures the
     *     embedded widget's c.options.number is always a string, even
     *     if the REST operation accidentally returns a number primitive.
     *     Matches the embedded widget's own defensive coercion in
     *     ./sp_widget_x_casemgmt_case_confirmation_widget.xml.
     */
    var c = this;

    // Initialize the form state with empty values for each whitelisted field.
    // The whitelist (subject, type, description, requester_name,
    // requester_email) matches exactly the fields accepted by
    // /api/x_casemgmt/case_submit per AAP Section 0.4.4 and 0.7.4.
    c.formData = {
        subject: '',
        type: '',
        description: '',
        requester_name: '',
        requester_email: ''
    };

    // Submission state flags. Initialized with safe defaults so the
    // template's ng-if and ng-disabled expressions evaluate cleanly
    // even before c.submit() runs.
    c.submitting = false;
    c.errorMessage = '';

    /**
     * Submit the form data to the scripted REST endpoint at
     * POST /api/x_casemgmt/case_submit.
     *
     * Per AAP Section 0.4.4: posts EXACTLY the five whitelisted fields
     * (subject, type, description, requester_name, requester_email).
     * No additional fields are sent.
     *
     * Per AAP Section 0.4.4: on success, flips c.data.submitted to true
     * and passes the returned case number to the embedded confirmation
     * widget via c.data.confirmationWidget.options.number. The embedded
     * widget renders the verbatim message "Your case has been submitted"
     * plus the case number.
     *
     * Per AAP Section 0.7.2 (information-leakage hardening): on any
     * error (HTTP 4xx/5xx, network, missing number on HTTP 200), sets
     * c.errorMessage to the generic string "Submission failed. Please
     * try again." This function MUST NOT echo error.data.error,
     * error.statusText, or any server-supplied text.
     */
    c.submit = function() {
        // Idempotent guard: prevent double-submit if the user clicks
        // the button or presses Enter while a request is in flight.
        // The button is also disabled in this case via ng-disabled,
        // but the guard provides defense-in-depth in case the disabled
        // state is bypassed by an edge browser's keyboard handling.
        if (c.submitting) {
            return;
        }

        // Reset state at the start of every submit. The error message
        // and submitting flag drive mutually-exclusive UI affordances.
        c.submitting = true;
        c.errorMessage = '';

        // POST to the scripted REST endpoint. The payload is built by
        // enumerating EXACTLY the five whitelisted fields - NOT by
        // passing c.formData wholesale - so any future expansion of
        // c.formData does not accidentally widen the payload surface.
        // This is defense-in-depth alongside the server-side whitelist
        // enforced by x_casemgmt.CasePortalService.submitCase().
        $http.post('/api/x_casemgmt/case_submit', {
            subject:          c.formData.subject,
            type:             c.formData.type,
            description:      c.formData.description,
            requester_name:   c.formData.requester_name,
            requester_email:  c.formData.requester_email
        }).then(function(response) {
            // Success path (HTTP 2xx). The server's REST operation
            // returns { number, message } per its contract.
            c.submitting = false;
            if (response && response.data && response.data.number) {
                // Pass the returned case number to the embedded
                // confirmation widget by mutating its options.number.
                // The embedded widget's controller assigns
                //   c.options = $scope.options;
                // so this mutation propagates reactively through
                // Angular's two-way binding.
                if (c.data.confirmationWidget && c.data.confirmationWidget.options) {
                    c.data.confirmationWidget.options.number = String(response.data.number);
                }
                // Mirror the case number on c.data for any consumer that
                // wants it directly. Defense-in-depth in case the
                // embedded widget's options object is replaced rather
                // than mutated by some future refactor.
                c.data.submittedNumber = String(response.data.number);
                // Flip the submitted flag - the template swaps from
                // the form panel to the embedded confirmation widget.
                c.data.submitted = true;
            } else {
                // Defensive: HTTP 200 but no case number in the body.
                // This should never happen if the REST operation
                // conforms to its contract (it always returns either
                // { number, message } on success or { error } on
                // failure), but the guard prevents a confusing UX
                // where the form vanishes without a confirmation.
                c.errorMessage = 'Submission failed. Please try again.';
            }
        }, function(error) {
            // Error path (HTTP 4xx, 5xx, or network failure / 0).
            // ALL error types are treated identically per the
            // information-leakage hardening discussed in the file
            // header comment. The generic error message is hardcoded
            // here in the controller; this function MUST NOT echo
            // error.data.error, error.statusText, or any server-
            // supplied content.
            c.submitting = false;
            c.errorMessage = 'Submission failed. Please try again.';
        });
    };
}
